body.query:
let pricePerGb = todouble('@{parameters('estimatedPricePerGb')}');
let cycleStart = startofmonth(now());
let cycleEnd   = endofmonth(now());
let cycle = Usage
| where TimeGenerated between (cycleStart .. cycleEnd)
| where IsBillable == true
| summarize GbCycle = sum(Quantity)/1024.0 by Solution;
let weekly = Usage
| where TimeGenerated >= ago(7d)
| where IsBillable == true
| summarize GbWeek = sum(Quantity)/1024.0;
cycle
| summarize TotalGbCycle=sum(GbCycle)
| extend GbLastWeek = toscalar(weekly), EstimatedCostCycle = round(TotalGbCycle * pricePerGb, 2)

Finalize_Email_Html.inputs:
@{replace(replace(outputs('Render_Email_Html'),
  '{{FOOTER_TEXT}}', coalesce(body('Parse_Customer_Config')?['footerText'], 'Generated by the Security Pulse Agent.')),
  '{{GENERATED_UTC}}', utcNow())}
